SELECT count(*) FROM title, cast_info, role_type, movie_companies, movie_keyword, company_type, kind_type, movie_info WHERE cast_info.movie_id = title.id AND cast_info.role_id = role_type.id AND movie_companies.movie_id = title.id AND movie_keyword.movie_id = title.id AND movie_companies.company_type_id = company_type.id AND title.kind_id = kind_type.id AND movie_info.movie_id = title.id;